#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
struct Pair
{
	int x,y;inline Pair(const int &xx=0,const int &yy=0){x=xx;y=yy;}
	inline bool operator<(const Pair&Q)const{return x==Q.x?y<Q.y:x<Q.x;}
	inline bool operator==(const Pair&Q)const{return x==Q.x&&y==Q.y;}
	inline bool operator<=(const Pair&Q)const{return x==Q.x?y<=Q.y:x<Q.x;}
};
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1e5+10,M=2e5+10,INF=0x3f3f3f3f;int n,m,a[55][55];
namespace MaxFlow_MaxCost
{
	int s,t,que[N*20],H,T,head[N],des[N<<1],nxt[N<<1],cap[N<<1],cgt=1,cst[N<<1],h2[N],mnc,f2[N],DN,dis[N];
	bool inq[N],vis[N];inline void Init(const int &n,const bool &S=0){DN=n+5;if(S)memset(head,0,DN*sizeof(int)),cgt=1,mnc=0;}
	inline void ins(const int &x,const int &y,const int &c,const int &w)
	{
		nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=c;cst[cgt]=w;
		nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;cst[cgt]=-w;
	}
	inline bool spfa()
	{
		memset(dis,-0x3f,DN*sizeof(int));dis[que[H=T=1]=s]=0;while(H<=T)
		{
			int u=que[H++];inq[u]=false;grep(u,i)
			{
				int v=des[i];if(cap[i]&&dis[u]+cst[i]>dis[v])
				{
					dis[v]=dis[u]+cst[i];
					if(!inq[v])inq[que[++T]=v]=true;
				}
			}
		}
		return dis[t]!=dis[0];
	}
	inline int dfs(const int &u=s,int in=INF)
	{
		if(u==t)return in;int out=0;vis[u]=true;for(int &i=h2[u];i;i=nxt[i])
		{
			int v=des[i];if(!vis[v]&&cap[i]&&dis[v]==dis[u]+cst[i])
			{
				int tmp=dfs(v,min(in,cap[i]));out+=tmp;in-=tmp;
				cap[i]-=tmp;cap[i^1]+=tmp;mnc+=tmp*cst[i];if(!in)break;
			}
		}
		if(!out)dis[u]=-INF;return vis[u]=false,out;
	}
	inline Pair dinic(int u,int v){s=u;t=v;int res=0;while(spfa())memcpy(h2,head,DN*sizeof(int)),res+=dfs();return Pair(res,mnc);}
}
using MaxFlow_MaxCost::ins;using MaxFlow_MaxCost::Init;using MaxFlow_MaxCost::dinic;
namespace Sub1
{
	inline int turn(int x,int y,bool q=0){return (x-1)*(n+m+1)+y+(q?(n+m+2)*(n+m+2):0);}
	inline void mian()
	{
		Init(2*(n+m+2)*(n+m+2)+2);int S=2*(n+m+2)*(n+m+2)+1,T=S+1;
		rep(1,m,i)ins(S,turn(1,i,0),1,0);
		rep(1,n,i)rep(1,i+m-1,j)ins(turn(i,j,0),turn(i,j,1),1,a[i][j]);
		rep(1,n-1,i)rep(1,i+m-1,j)
		{
			ins(turn(i,j,1),turn(i+1,j,0),1,0);
			ins(turn(i,j,1),turn(i+1,j+1,0),1,0);
		}
		rep(1,m+n-1,i)ins(turn(n,i,1),T,1,0);printf("%d\n",dinic(S,T).y);
	}
}
namespace Sub2
{
	inline int turn(int x,int y){return (x-1)*(n+m+1)+y;}
	inline void mian()
	{
		Init((n+m+2)*(n+m+2)+2,1);int S=(n+m+2)*(n+m+2)+1,T=S+1;
		rep(1,m,i)ins(S,turn(1,i),1,a[1][i]);
		rep(1,n-1,i)rep(1,i+m-1,j)
		{
			ins(turn(i,j),turn(i+1,j),1,a[i+1][j]);
			ins(turn(i,j),turn(i+1,j+1),1,a[i+1][j+1]);
		}
		rep(1,n+m-1,i)ins(turn(n,i),T,1919810,0);printf("%d\n",dinic(S,T).y);
	}
}
namespace Sub3
{
	inline int turn(int x,int y){return (x-1)*(n+m+1)+y;}
	inline void mian()
	{
		Init((n+m+2)*(n+m+2)+2,1);int S=(n+m+2)*(n+m+2)+1,T=S+1;
		rep(1,m,i)ins(S,turn(1,i),1,a[1][i]);
		rep(1,n-1,i)rep(1,i+m-1,j)
		{
			ins(turn(i,j),turn(i+1,j),114514,a[i+1][j]);
			ins(turn(i,j),turn(i+1,j+1),114514,a[i+1][j+1]);
		}
		rep(1,n+m-1,i)ins(turn(n,i),T,114514,0);printf("%d\n",dinic(S,T).y);
	}
}
int main()
{
	m=read();n=read();rep(1,n,i)rep(1,i+m-1,j)a[i][j]=read();
	Sub1::mian();Sub2::mian();Sub3::mian();return 0;
}
